1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
14	
15	const CURSE_SURCHARGE_RATE = 0.5;
16	
17	type Scenario = {
18	  customer: { yearsWithMHPCO: number };
19	  steps: Array<{ op: "quote"; items: Item[] }>;
20	};
21	
22	type QuoteResult = { premium: number };
23	
24	const COMPONENT_BLOCK_SIZE = 3;
25	const COMPONENT_BLOCK_PREMIUM = 60;
26	
27	const formsComponentBlock = (items: Item[]): boolean =>
28	  items.length === COMPONENT_BLOCK_SIZE && items.every((item) => item.type === items[0].type);
29	
30	const sumOfBasePremiums = (items: Item[]): number =>
31	  items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
32	
33	const groupByType = (items: Item[]): Item[][] => {
34	  const groups = new Map<string, Item[]>();
35	  for (const item of items) {
36	    const existing = groups.get(item.type);
37	    if (existing) existing.push(item);
38	    else groups.set(item.type, [item]);
39	  }
40	  return [...groups.values()];
41	};
42	
43	const basePremiumForGroup = (group: Item[]): number =>
44	  formsComponentBlock(group) ? COMPONENT_BLOCK_PREMIUM : sumOfBasePremiums(group);
45	
46	const basePremiumFor = (items: Item[]): number =>
47	  groupByType(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);
48	
49	const curseSurchargeFor = (items: Item[]): number =>
50	  items.reduce(
51	    (sum, item) => (item.cursed ? sum + BASE_PREMIUMS[item.type] * CURSE_SURCHARGE_RATE : sum),
52	    0,
53	  );
54	
55	const quotePremium = (items: Item[]): QuoteResult => {
56	  const base = basePremiumFor(items);
57	  const curse = curseSurchargeFor(items);
58	  return { premium: Math.ceil(base + curse + base * FIRST_INSURANCE_RATE + PROCESSING_FEE) };
59	};
60	
61	export const processScenario = (scenario: Scenario): { results: QuoteResult[] } => {
62	  const results = scenario.steps.map((step) => quotePremium(step.items));
63	  return { results };
64	};
